import redis
import getpass

def create_redis_client():
    host = input("Enter Redis host (default: localhost): ") or "localhost"
    port = input("Enter Redis port (default: 6379): ") or 6379
    password = getpass.getpass("Enter Redis password (leave blank if none): ")
    
    return redis.StrictRedis(host=host, port=int(port), password=password, decode_responses=True)

